input.command:
powershell -Command "
$pdf = 'C:\Users\Administrator\Desktop\1cellAssembleMachine\기존 프로젝트 전 파일 내보내기 한거.pdf'
if (Test-Path $pdf) {
    $acro = New-Object -ComObject AcroExch.PDDoc
    $acro.Open($pdf) | Out-Null
    $pages = $acro.GetNumPages()
    Write-Host \"PDF 총 페이지: $pages\"
    $acro.Close()
} else {
    Write-Host 'File not found'
}
" 2>&1
